import 'dart:io'; import 'dart:convert'; void main() async { var req = await HttpClient().getUrl(Uri.parse('https://raw.githubusercontent.com/dreadnought/python-daly-bms/main/dalybms/daly_bms.py')); var res = await req.close(); var body = await res.transform(utf8.decoder).join(); var lines = body.split('\n'); for (var i = 0; i < lines.length; i++) { if (lines[i].toLowerCase().contains('94') || lines[i].toLowerCase().contains('cycle') || lines[i].toLowerCase().contains('health') || lines[i].toLowerCase().contains('soh')) { print([i, lines[i].trim()]); } } }